import jwt  # PyJWT
from functools import wraps
from flask import request, abort

SECRET = "super-secret-signing-key"

def require_tenant(f):
    """Decorator: extract and validate tenant_id from a signed JWT."""
    @wraps(f)
    def wrapper(*args, **kwargs):
        auth = request.headers.get("Authorization", "")
        if not auth.startswith("Bearer "):
            abort(401)
        token = auth[7:]
        try:
            payload = jwt.decode(token, SECRET, algorithms=["HS256"])
        except jwt.InvalidTokenError:
            abort(403)
        # Attach tenant_id to every downstream call
        request.tenant_id = payload["tenant_id"]
        return f(*args, **kwargs)
    return wrapper

@app.route("/chat", methods=["POST"])
@require_tenant
def chat():
    tenant_id = request.tenant_id
    # All context retrieval and history lookups are scoped to tenant_id
    context = retrieve_context(request.json["query"], tenant_id=tenant_id)
    history = load_history(session_id=request.json["session_id"], tenant_id=tenant_id)
    return generate_response(context, history)

