# Secure function-call handler: validate schema, authorize user, audit log.
from pydantic import BaseModel, ValidationError
import logging

logger = logging.getLogger("function_audit")

class GetOrderArgs(BaseModel):
    order_id: str  # Pydantic validates type; add regex if needed

def handle_get_order(raw_args: dict, authenticated_user_id: str) -> dict:
    # 1. Validate schema — reject malformed LLM output
    try:
        args = GetOrderArgs(**raw_args)
    except ValidationError as e:
        raise ValueError(f"Invalid function arguments: {e}") from e

    # 2. Authorize: ensure the order belongs to the requesting user
    order = db.get_order(args.order_id)
    if order is None or order.user_id != authenticated_user_id:
        logger.warning(
            "Unauthorized order access attempt",
            extra={"user": authenticated_user_id, "order": args.order_id},
        )
        raise PermissionError("Order not found or access denied.")

    # 3. Audit log
    logger.info(
        "get_order called",
        extra={"user": authenticated_user_id, "order": args.order_id},
    )
    return {"order_id": order.id, "status": order.status, "total": order.total}
